  function friendlyDateTime(dateTimeish) {
    if (DateTime.isDateTime(dateTimeish)) {
      return dateTimeish;
    } else if (dateTimeish && dateTimeish.valueOf && isNumber2(dateTimeish.valueOf())) {
      return DateTime.fromJSDate(dateTimeish);
    } else if (dateTimeish && typeof dateTimeish === "object") {
      return DateTime.fromObject(dateTimeish);
    } else {
      throw new InvalidArgumentError(
        `Unknown datetime argument: ${dateTimeish}, of type ${typeof dateTimeish}`
      );
    }
  }

  // src/js/modules/module-countdown.js
  function countdown() {
    const days = document.querySelector("#days");
    const hours = document.querySelector("#hours");
    const minutes = document.querySelector("#minutes");
    const seconds = document.querySelector("#seconds");
    const module = document.querySelector(".countdown");
    const count = setInterval(() => {
      const now2 = DateTime.now().setZone("Europe/Madrid");
      const finalDate = DateTime.fromObject(
        {
          year: days.dataset.year,
          month: days.dataset.month,
          day: days.dataset.day,
          hour: hours.dataset.hour,
          minute: minutes.dataset.minute,
          second: seconds.dataset.second
        },
        { zone: "Europe/Madrid" }
      );
      const diffDuration = finalDate.diff(now2, ["days", "hours", "minutes", "seconds"]).toObject();
      days.innerHTML = diffDuration.days;
      hours.innerHTML = diffDuration.hours;
      minutes.innerHTML = diffDuration.minutes;
      seconds.innerHTML = Math.round(diffDuration.seconds);
      if (finalDate.equals(diffDuration)) {
        clearInterval(count);
        module.style.display = "none";
      }
    }, 1e3);
  }

