  var SliderRows = class {
    constructor() {
      this.sliderInstances = [];
      try {
        this.topRow = document.querySelector(".slider__row1");
        this.bottomRow = document.querySelector(".slider__row2");
        if (!this.topRow && !this.bottomRow) {
          throw new Error("No slider rows found (.slider__row1, .slider__row2)");
        }
        this.optionsTop = {
          drag: true,
          type: "loop",
          pagination: false,
          arrows: false,
          autoWidth: true,
          gap: 40,
          focus: "center",
          breakpoints: {
            992: {
              autoWidth: false,
              focus: false,
              perPage: 1,
              padding: {
                left: 20,
                right: 40
              },
              gap: 10
            }
          }
        };
        this.optionsBottom = {
          drag: true,
          type: "loop",
          pagination: false,
          arrows: false,
          autoWidth: true,
          gap: 40,
          breakpoints: {
            992: {
              autoWidth: false,
              focus: false,
              perPage: 1,
              padding: {
                left: 40,
                right: 20
              },
              gap: 10
            }
          }
        };
        this.init();
      } catch (error) {
        console.error("SliderRows initialization error:", error);
      }
    }
    init() {
      try {
        if (this.topRow) {
          this.initSlider(this.topRow, this.optionsTop);
        }
        if (this.bottomRow) {
          this.initSlider(this.bottomRow, this.optionsBottom);
        }
      } catch (error) {
        console.error("Error initializing sliders:", error);
      }
    }
    initSlider(row, options) {
      try {
        if (!row) return;
        const splide = row.querySelector(".splide");
        if (!splide) {
          throw new Error(`Splide element not found in ${row.className}`);
        }
        const instance = new Splide(splide, options);
        instance.mount();
        this.sliderInstances.push(instance);
        this.tabController(row, instance);
      } catch (error) {
        console.error("Error initializing slider:", error);
      }
    }
    tabController(row, instance) {
      try {
        if (!row || !instance) return;
        const tabs = row.querySelectorAll(".btn__tabs");
        if (!tabs.length) return;
        tabs.forEach((tab, index) => {
          tab.addEventListener("click", () => {
            try {
              for (const t5 of tabs) {
                t5.classList.remove("active");
              }
              instance.go(index);
              tab.classList.add("active");
            } catch (err) {
              console.error("Error handling tab click:", err);
            }
          });
        });
        const hasActiveTab = Array.from(tabs).some(
          (tab) => tab.classList.contains("active")
        );
        if (!hasActiveTab && tabs.length > 0) {
          tabs[0].classList.add("active");
        }
      } catch (error) {
        console.error("Error setting up tab controllers:", error);
      }
    }
    // Clean up method to prevent memory leaks
    destroy() {
      try {
        for (const instance of this.sliderInstances) {
          if (instance && typeof instance.destroy === "function") {
            instance.destroy();
          }
        }
        this.sliderInstances = [];
      } catch (error) {
        console.error("Error destroying slider instances:", error);
      }
    }
  };

