  function initTabSystem() {
    console.log("initTabSystem");
    const wrappers = document.querySelectorAll('[data-tabs="wrapper"]');
    for (const wrapper of wrappers) {
      let startProgressBar = function(index) {
        if (progressBarTween) progressBarTween.kill();
        const bar = contentItems[index].querySelector(
          '[data-tabs="item-progress"]'
        );
        if (!bar) return;
        gsapWithCSS.set(bar, { scaleX: 0, transformOrigin: "left center" });
        progressBarTween = gsapWithCSS.to(bar, {
          scaleX: 1,
          duration: autoplayDuration / 1e3,
          ease: "power1.inOut",
          onComplete: () => {
            if (!isAnimating) {
              const nextIndex = (index + 1) % contentItems.length;
              switchTab(nextIndex);
            }
          }
        });
      }, switchTab = function(index) {
        if (isAnimating || contentItems[index] === activeContent) return;
        isAnimating = true;
        if (progressBarTween) progressBarTween.kill();
        const outgoingContent = activeContent;
        const outgoingVisual = activeVisual;
        const outgoingBar = outgoingContent?.querySelector(
          '[data-tabs="item-progress"]'
        );
        const incomingContent = contentItems[index];
        const incomingVisual = visualItems[index];
        const incomingBar = incomingContent.querySelector(
          '[data-tabs="item-progress"]'
        );
        outgoingContent?.classList.remove("active");
        outgoingVisual?.classList.remove("active");
        incomingContent.classList.add("active");
        incomingVisual.classList.add("active");
        const tl = gsapWithCSS.timeline({
          defaults: { duration: 0.65, ease: "power3" },
          onComplete: () => {
            activeContent = incomingContent;
            activeVisual = incomingVisual;
            isAnimating = false;
            if (autoplay) startProgressBar(index);
          }
        });
        if (outgoingContent) {
          outgoingContent.classList.remove("active");
          outgoingVisual?.classList.remove("active");
          tl.set(outgoingBar, { transformOrigin: "right center" }).to(outgoingBar, { scaleX: 0, duration: 0.3 }, 0).to(outgoingVisual, { autoAlpha: 0, xPercent: 3 }, 0).to(
            outgoingContent.querySelector('[data-tabs="item-details"]'),
            { height: 0 },
            0
          );
        }
        incomingContent.classList.add("active");
        incomingVisual.classList.add("active");
        tl.fromTo(
          incomingVisual,
          { autoAlpha: 0, xPercent: 3 },
          { autoAlpha: 1, xPercent: 0 },
          0.3
        ).fromTo(
          incomingContent.querySelector('[data-tabs="item-details"]'),
          { height: 0 },
          { height: "auto" },
          0
        ).set(incomingBar, { scaleX: 0, transformOrigin: "left center" }, 0);
      };
      const contentItems = wrapper.querySelectorAll('[data-tabs="content-item"]');
      const visualItems = wrapper.querySelectorAll('[data-tabs="visual-item"]');
      const autoplay = wrapper.dataset.tabsAutoplay === "true";
      const autoplayDuration = Number.parseInt(wrapper.dataset.tabsAutoplayDuration) || 5e3;
      let activeContent = null;
      let activeVisual = null;
      let isAnimating = false;
      let progressBarTween = null;
      switchTab(0);
      for (const [i6, item] of contentItems.entries()) {
        item.addEventListener("click", () => {
          if (item === activeContent) return;
          switchTab(i6);
        });
      }
    }
  }

